  "p05.cat.sig": { id: "Iced Aren Latte, Butterscotch Latte, Pandan Latte", en: "Iced Aren Latte, Butterscotch Latte, Pandan Latte" },
  "p05.cat.coffee": { id: "Caramel Latte, Hazelnut Latte, Vanilla Latte", en: "Caramel Latte, Hazelnut Latte, Vanilla Latte" },
