  "p04cara.step.price": { id: "Compare unit_price vs menu master price list", en: "Compare unit_price vs menu master price list" },
  "p04cara.step.missing": { id: "NULL/empty check pada kolom outlet_id", en: "NULL/empty check on outlet_id column" },
