  "p04cara.step.future": { id: "transaction_date > max_period filter", en: "transaction_date > max_period filter" },
  "p04cara.cleaning.insight": { id: "Total 95 anomali dari 16,323 rows = 0.58% error rate. Data retention 99.42%. Setiap anomali punya alasan realistis — ini bukan random noise, tapi masalah umum di POS system multi-outlet.", en: "Total 95 anomalies from 16,323 rows = 0.58% error rate. Data retention 99.42%. Each anomaly has a realistic cause — this isn't random noise, but common issues in multi-outlet POS systems." },
