  "p07.sec.summary": { id: "Job Summary", en: "Job Summary" },
  "p07.summary.text": { id: "Operation Analyst Officer berperan sebagai analytics partner untuk tim Operations Fore Coffee — menerjemahkan data store operations, supply chain, dan product performance menjadi actionable insights. Role ini bertanggung jawab membangun dashboard, melakukan analisis mendalam terhadap performa outlet dan supply chain, serta memberikan rekomendasi data-driven untuk meningkatkan efisiensi operasional, produktivitas store, dan customer experience.", en: "The Operation Analyst Officer serves as an analytics partner to Fore Coffee's Operations team — translating store operations, supply chain, and product performance data into actionable insights. This role is responsible for building dashboards, conducting in-depth analysis of outlet and supply chain performance, and delivering data-driven recommendations to improve operational efficiency, store productivity, and customer experience." },
  "p07.summary.text2": { id: "Incumbent akan bekerja erat dengan tim Store Operations, Supply Chain, Product, dan Finance untuk memastikan keputusan operasional didasarkan pada data yang akurat, tepat waktu, dan relevan.", en: "The incumbent will work closely with Store Operations, Supply Chain, Product, and Finance teams to ensure operational decisions are grounded in accurate, timely, and relevant data." },
