// ── Lang Toggle Engine ──
(function () {
  const STORAGE_KEY = "forecoffee-lang";
  let currentLang = localStorage.getItem(STORAGE_KEY) || "id";

  function applyLang(lang) {
    currentLang = lang;
    localStorage.setItem(STORAGE_KEY, lang);
    document.documentElement.lang = lang;

    document.querySelectorAll("[data-i18n]").forEach(function(el) {
      var key = el.getAttribute("data-i18n");
      var t = window.translations[key];
      if (t && t[lang] !== undefined) {
        el.innerHTML = t[lang];
      }
    });

    var btn = document.getElementById("langToggle");
    if (btn) {
      btn.textContent = lang === "id" ? "EN" : "ID";
      btn.title = lang === "id" ? "Switch to English" : "Ganti ke Bahasa Indonesia";
    }
  }

  function createToggle() {
    var topbar = document.querySelector(".topbar");
    if (!topbar) return;

    var btn = document.createElement("button");
    btn.id = "langToggle";
    btn.className = "lang-toggle";
    btn.addEventListener("click", function() {
      applyLang(currentLang === "id" ? "en" : "id");
    });
    topbar.appendChild(btn);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function() { createToggle(); applyLang(currentLang); });
  } else {
    createToggle();
    applyLang(currentLang);
  }
})();
